--
-- Table structure for table `income_transactions`
--

DROP TABLE IF EXISTS `income_transactions`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `income_transactions` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `invoice_number` varchar(40) COLLATE utf8mb4_unicode_ci NOT NULL,
  `trx_date` date NOT NULL,
  `doctor_id` bigint unsigned NOT NULL,
  `patient_id` bigint unsigned DEFAULT NULL,
  `payer_type` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'umum',
  `ortho_case_mode` varchar(20) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'none',
  `status` enum('draft','paid','cancelled','void') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'paid',
  `bill_total` decimal(15,2) NOT NULL DEFAULT '0.00',
  `doctor_fee_total` decimal(15,2) NOT NULL DEFAULT '0.00',
  `pay_total` decimal(15,2) NOT NULL DEFAULT '0.00',
  `visibility` enum('public','private') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'public',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `created_by` bigint unsigned NOT NULL,
  `receipt_verify_code` varchar(80) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `receipt_pdf_path` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `income_transactions_invoice_number_unique` (`invoice_number`),
  UNIQUE KEY `income_transactions_receipt_verify_code_unique` (`receipt_verify_code`),
  KEY `income_transactions_created_by_foreign` (`created_by`),
  KEY `income_transactions_trx_date_index` (`trx_date`),
  KEY `income_transactions_doctor_id_index` (`doctor_id`),
  KEY `income_transactions_patient_id_index` (`patient_id`),
  KEY `income_transactions_status_index` (`status`),
  KEY `income_transactions_visibility_index` (`visibility`),
  CONSTRAINT `income_transactions_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`),
  CONSTRAINT `income_transactions_doctor_id_foreign` FOREIGN KEY (`doctor_id`) REFERENCES `doctors` (`id`),
  CONSTRAINT `income_transactions_patient_id_foreign` FOREIGN KEY (`patient_id`) REFERENCES `patients` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=132 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

